mapper.select:
SELECT 
FROM vso_config_timeout t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.config_key = #{configKey}


    AND t.enable_flag = #{enableFlag}

ORDER BY t.id DESC

